// Extract form data
// Expected fields: prospectName, date, services (array or string),
// discountLevel ('Discount' | 'Retail' | 'Premium'),
// requestorName (format: "Full Name (user@example.com)")
const formData = $('Pricing Request Webhook').item.json.body;
const prospectName   = formData.prospectName;
const date           = formData.date;
const selectedServices = Array.isArray(formData.services) ? formData.services : [formData.services];
const discountLevel  = formData.discountLevel; // 'Discount', 'Retail', or 'Premium'
const requestorInfo  = formData.requestorName; // e.g. "Jane Smith (user@example.com)"

// Extract email from requestor info
const emailMatch    = requestorInfo.match(/\(([^)]+)\)/);
const requestorEmail = emailMatch ? emailMatch[1] : '';
const requestorName  = requestorInfo.replace(/\s*\([^)]*\)/, '').trim();

// Get pricing data from Excel node
// Expected columns: Title, Description, Cost, Discount, Retail, Premium, Unit
const pricingData = $('Fetch Pricing Sheet').all();

// Filter pricing data for selected services (match on 'Title' column)
const filteredPricing = pricingData.filter(item => {
  const service = item.json.Title;
  return selectedServices.includes(service);
});

// Map pricing based on discount level
const processedPricing = filteredPricing.map(item => {
  const data = item.json;
  let price;
  switch (discountLevel) {
    case 'Discount': price = data.Discount; break;
    case 'Premium':  price = data.Premium;  break;
    default:         price = data.Retail;
  }
  return {
    service:     data.Title,
    description: data.Description,
    cost:        data.Cost,
    price:       price,
    unit:        data.Unit
  };
});

// Calculate total
const total = processedPricing.reduce((sum, item) => sum + (parseFloat(item.price) || 0), 0);

return [{
  json: {
    prospectName,
    date,
    requestorName,
    requestorEmail,
    discountLevel,
    selectedServices,
    pricingItems: processedPricing,
    total: total.toFixed(2)
  }
}];
